// Center-dot HUD element. Soft circle at each detection's centre,
// coverage falls off linearly with distance. `radius_px` is the dot
// radius in 1080p-reference pixels (legacy: px_u * 4 → radius_px=4).

struct U {
    color_r: f32,
    color_g: f32,
    color_b: f32,
    alpha: f32,
    radius_px: f32,
    blob_count: u32,
    _pad0: u32,
    _pad1: u32,
};

struct Detection {
    x: f32,
    y: f32,
    width: f32,
    height: f32,
};

@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var<storage, read> detections: array<Detection>;
@group(0) @binding(2) var source_tex: texture_2d<f32>;
@group(0) @binding(3) var src_sampler: sampler;
@group(0) @binding(4) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if gid.x >= dims.x || gid.y >= dims.y { return; }
    let uv = (vec2<f32>(gid.xy) + 0.5) / vec2<f32>(dims);
    var src = textureSampleLevel(source_tex, src_sampler, uv, 0.0);

    let dpi_scale = f32(dims.y) / 1080.0;
    let radius = u.radius_px * (1.0 / f32(dims.x)) * dpi_scale;

    var coverage = 0.0;
    let n = min(u.blob_count, 8u);
    for (var i: u32 = 0u; i < n; i = i + 1u) {
        let d = detections[i];
        if d.width < 0.0001 && d.height < 0.0001 { continue; }
        let center = vec2<f32>(d.x + d.width * 0.5, d.y + d.height * 0.5);
        let dist = length(uv - center);
        coverage = max(coverage, 1.0 - saturate(dist / radius));
    }

    let add = coverage * u.alpha;
    src = vec4<f32>(
        src.r + u.color_r * add,
        src.g + u.color_g * add,
        src.b + u.color_b * add,
        src.a,
