// Size-gauge HUD element. Anti-aliased outlined rectangle + interior
// fill drawn below each detection bbox, fill fraction proportional to
// bbox area. `bottom_offset_px` is the gap between bbox bottom and
// the bar (legacy=50); `bar_height_px` is the bar height (legacy=8);
// `min_bar_width_px` floors the bar width so tiny detections still
// get a readable bar (legacy=80); `fill_scale` multiplies (w*h) into
// the [0,1] fill fraction (legacy=20).

struct U {
    color_r: f32,
    color_g: f32,
    color_b: f32,
    alpha: f32,
    bottom_offset_px: f32,
    bar_height_px: f32,
    min_bar_width_px: f32,
    fill_scale: f32,
    thickness_px: f32,
    blob_count: u32,
    _pad0: u32,
    _pad1: u32,
};

struct Detection {
    x: f32,
    y: f32,
    width: f32,
    height: f32,
};

@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var<storage, read> detections: array<Detection>;
@group(0) @binding(2) var source_tex: texture_2d<f32>;
@group(0) @binding(3) var src_sampler: sampler;
@group(0) @binding(4) var output_tex: texture_storage_2d<rgba16float, write>;

fn line_seg(p: vec2<f32>, a: vec2<f32>, b: vec2<f32>, thickness: f32) -> f32 {
    let pa = p - a;
    let ba = b - a;
    let len_sq = dot(ba, ba);
    if len_sq < 0.000001 { return 0.0; }
    let h = saturate(dot(pa, ba) / len_sq);
    let d = length(pa - ba * h);
    return 1.0 - saturate(d / thickness);
