// Subtle scanline overlay across the whole frame. Brightness modulates
// by a horizontal repeating pattern. `period_px` controls scanline
// density in pixels (legacy = 1 / (resolution.y * 0.5), i.e. ~2 px
// between scanlines); `intensity` is the additive contribution
// (legacy = 0.04).

struct U {
    color_r: f32,
    color_g: f32,
    color_b: f32,
    alpha: f32,
    period_px: f32,
    intensity: f32,
    _pad0: f32,
    _pad1: f32,
};

@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var source_tex: texture_2d<f32>;
@group(0) @binding(2) var src_sampler: sampler;
@group(0) @binding(3) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if gid.x >= dims.x || gid.y >= dims.y { return; }
    let uv = (vec2<f32>(gid.xy) + 0.5) / vec2<f32>(dims);
    var src = textureSampleLevel(source_tex, src_sampler, uv, 0.0);

    let scanline = abs(fract(uv.y * f32(dims.y) / u.period_px) - 0.5) * 2.0;
    let scan_alpha = (1.0 - smoothstep(0.4, 0.5, scanline)) * u.intensity;

    let add = scan_alpha * u.alpha;
    src = vec4<f32>(
        src.r + u.color_r * add,
        src.g + u.color_g * add,
        src.b + u.color_b * add,
        src.a,
    );
    textureStore(output_tex, vec2<i32>(gid.xy), src);
}
